# Golden test validator for R implementations
# Based on the methodology in GOLDEN_TESTS.md

library(xml2)

#' Validate a golden test against an R implementation
#'
#' @param xml_path Path to the golden test XML file
#' @param implementation_result Result from the R implementation to validate
#' @param tolerance_override Override for all tolerance values (optional)
#' @return Logical indicating whether all checks passed
validate_golden_test <- function(xml_path, implementation_result, tolerance_override = NULL) {
  # Parse the XML file
  test_data <- parse_golden_test(xml_path)

  # Run all numeric checks
  checks <- test_data$expected_outputs$numeric_checks
  all_passed <- TRUE

  for (check in checks) {
    result <- perform_numeric_check(implementation_result, check, tolerance_override)
    if (!result) {
      cat("FAILED:", check$type, "check at", check$location, "\n")
      cat("  Expected:", check$expected, "Tolerance:", check$tolerance, "\n")
      all_passed <- FALSE
    } else {
      cat("PASSED:", check$type, "check at", check$location, "\n")
    }
  }

  if (all_passed) {
    cat("All golden test checks PASSED\n")
  } else {
    cat("Some golden test checks FAILED\n")
  }

  return(all_passed)
}

#' Parse a golden test XML file
#'
#' @param xml_path Path to the XML file
#' @return List containing parsed test data
parse_golden_test <- function(xml_path) {
  doc <- xml2::read_xml(xml_path)

  # Extract metadata
  metadata <- list(
    id = xml2::xml_text(xml2::xml_find_first(doc, ".//id")),
    version = xml2::xml_text(xml2::xml_find_first(doc, ".//version")),
    description = xml2::xml_text(xml2::xml_find_first(doc, ".//description"))
  )

  # Extract semantic description
  semantic_desc <- list(
    purpose = xml2::xml_text(xml2::xml_find_first(doc, ".//purpose")),
    algorithm = xml2::xml_text(xml2::xml_find_first(doc, ".//algorithm"))
  )

  # Extract inputs
  input_nodes <- xml2::xml_find_all(doc, ".//inputs/input")
  inputs <- lapply(input_nodes, function(node) {
    list(
      name = xml2::xml_attr(node, "name"),
      type = xml2::xml_attr(node, "type"),
      description = xml2::xml_text(xml2::xml_find_first(node, "description")),
      value = xml2::xml_text(xml2::xml_find_first(node, "value"))
    )
  })

  # Extract expected outputs and checks
  check_nodes <- xml2::xml_find_all(doc, ".//numeric_checks/check")
  checks <- lapply(check_nodes, function(node) {
    check <- list(
      type = xml2::xml_text(xml2::xml_find_first(node, "type")),
      location = xml2::xml_text(xml2::xml_find_first(node, "location"))
    )

    # Optional fields
    expected_node <- xml2::xml_find_first(node, "expected")
    if (!is.na(expected_node)) {
      check$expected <- as.numeric(xml2::xml_text(expected_node))
    }

    tolerance_node <- xml2::xml_find_first(node, "tolerance")
    if (!is.na(tolerance_node)) {
      check$tolerance <- as.numeric(xml2::xml_text(tolerance_node))
    }

    min_node <- xml2::xml_find_first(node, "min")
    if (!is.na(min_node)) {
      check$min <- as.numeric(xml2::xml_text(min_node))
    }

    max_node <- xml2::xml_find_first(node, "max")
    if (!is.na(max_node)) {
      check$max <- as.numeric(xml2::xml_text(max_node))
    }

    property_node <- xml2::xml_find_first(node, "property")
    if (!is.na(property_node)) {
      check$property <- xml2::xml_text(property_node)
    }

    return(check)
  })

  return(list(
    metadata = metadata,
    semantic_description = semantic_desc,
    inputs = inputs,
    expected_outputs = list(numeric_checks = checks)
  ))
}

#' Perform a single numeric check
#'
#' @param data The implementation result data
#' @param check The check specification
#' @param tolerance_override Override tolerance value
#' @return Logical indicating whether the check passed
perform_numeric_check <- function(data, check, tolerance_override = NULL) {
  # Extract the value to check based on location
  check_value <- extract_value_by_location(data, check$location)

  # Use override tolerance if provided
  tolerance <- if (!is.null(tolerance_override)) {
    tolerance_override
  } else {
    check$tolerance %||% 1e-10
  }

  # Perform the appropriate check type
  switch(check$type,
    "exact_value" = {
      abs(check_value - check$expected) < tolerance
    },
    "approximate" = {
      abs(check_value - check$expected) < tolerance
    },
    "range" = {
      check_value >= check$min && check_value <= check$max
    },
    "statistical" = {
      perform_statistical_check(data, check, tolerance)
    },
    "dimensional" = {
      perform_dimensional_check(data, check)
    },
    {
      warning(paste("Unknown check type:", check$type))
      FALSE
    }
  )
}

#' Extract value from data based on location string
#'
#' @param data The data object
#' @param location Location specification (e.g., "length(output)", "mean(output)")
#' @return The extracted value
extract_value_by_location <- function(data, location) {
  # Simple location parsing - extend as needed
  # This is a basic implementation that handles common cases

  if (location == "length(output)") {
    return(length(data))
  } else if (location == "sum(output)") {
    return(sum(data))
  } else if (location == "mean(output)") {
    return(mean(data))
  } else if (location == "max(output)") {
    return(max(data))
  } else if (location == "min(output)") {
    return(min(data))
  } else if (location == "sd(output)") {
    return(sd(data))
  } else if (location == "var(output)") {
    return(var(data))
  } else if (grepl("^output\\[", location)) {
    # Handle array indexing like output[1], output[5]
    idx_match <- regmatches(location, regexpr("\\d+", location))
    if (length(idx_match) > 0) {
      idx <- as.numeric(idx_match[1])
      return(data[idx])
    }
  }

  # Fallback: try to evaluate the location as R code
  # WARNING: This is potentially unsafe - only use with trusted input
  tryCatch({
    output <- data  # Make 'output' available in the evaluation environment
    eval(parse(text = location))
  }, error = function(e) {
    warning(paste("Could not evaluate location:", location, "Error:", e$message))
    NA
  })
}

#' Perform statistical property check
#'
#' @param data The data object
#' @param check The check specification
#' @param tolerance Tolerance value
#' @return Logical indicating whether the check passed
perform_statistical_check <- function(data, check, tolerance) {
  property_value <- switch(check$property,
    "mean" = mean(data),
    "standard_deviation" = sd(data),
    "variance" = var(data),
    "median" = median(data),
    "quantile_25" = quantile(data, 0.25),
    "quantile_75" = quantile(data, 0.75),
    {
      warning(paste("Unknown statistical property:", check$property))
      return(FALSE)
    }
  )

  abs(property_value - check$expected) < tolerance
}

#' Perform dimensional check
#'
#' @param data The data object
#' @param check The check specification
#' @return Logical indicating whether the check passed
perform_dimensional_check <- function(data, check) {
  if (check$location == "ncol(output)") {
    return(ncol(data) == check$expected)
  } else if (check$location == "nrow(output)") {
    return(nrow(data) == check$expected)
  } else if (check$location == "length(output)") {
    return(length(data) == check$expected)
  } else if (check$location == "dim(output)") {
    expected_dims <- eval(parse(text = check$expected))
    return(all(dim(data) == expected_dims))
  }

  FALSE
}

